mapper.select:
SELECT b.*, m.member_id, m.name AS member_name FROM board b JOIN member m ON b.member_no = m.no WHERE b.board_type = 'REVIEW'
AND b.is_deleted = #{searchDeleted}
AND b.title LIKE '%' || #{keyword} || '%'
AND m.member_id = #{keyword}
ORDER BY b.no DESC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

